#!/usr/bin/env node
/**
 * Derive per-project publish/update timestamps from the git history of each
 * English source file and write them to src/data/project-dates.json, consumed
 * at build time by the project pages.
 *
 * Only the `en/` source carries authoring history; the `pt/`/`es/` siblings are
 * regenerated by the translator and their timestamps are meaningless, so dates
 * always come from the English file and apply to every locale.
 *
 * Shallow clones (CI, most hosts) cannot see the first commit, which would make
 * the "published" date wrong. In that case the script no-ops and the committed
 * JSON is used as-is. Regenerate locally (full history) and commit the result.
 */
import { execFileSync } from 'node:child_process';
import { mkdir, readdir, writeFile } from 'node:fs/promises';
import { dirname, join, relative } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const repoRoot = join(__dirname, '..');
const projectsDir = join(repoRoot, 'src/content/projects/en');
const outFile = join(repoRoot, 'src/data/project-dates.json');

function git(args) {
  return execFileSync('git', args, { cwd: repoRoot, encoding: 'utf-8' }).trim();
}

function isShallowOrUnavailable() {
  try {
    return git(['rev-parse', '--is-shallow-repository']) !== 'false';
  } catch {
    return true;
  }
}

async function main() {
  if (isShallowOrUnavailable()) {
    console.log(
      'build-git-dates: shallow clone or git unavailable; keeping committed project-dates.json.',
    );
    return;
  }

  let entries;
  try {
    entries = await readdir(projectsDir, { withFileTypes: true });
  } catch {
    console.log('build-git-dates: no projects/en directory; nothing to do.');
    return;
  }

  const files = entries
    .filter((e) => e.isFile() && /\.(md|mdx)$/.test(e.name))
    .map((e) => e.name)
    .sort();

  const dates = {};
  for (const name of files) {
    const slug = name.replace(/\.(md|mdx)$/, '');
    const rel = relative(repoRoot, join(projectsDir, name));
    let log;
    try {
      log = git(['log', '--follow', '--format=%aI', '--', rel]);
    } catch {
      continue;
    }
    const stamps = log
      .split('\n')
      .map((s) => s.trim())
      .filter(Boolean);
    // Empty history means the file is staged but not yet committed; skip it
    // rather than invent a date.
    if (stamps.length === 0) continue;
    dates[slug] = { published: stamps[stamps.length - 1], updated: stamps[0] };
  }

  const sorted = Object.fromEntries(
    Object.keys(dates)
      .sort()
      .map((k) => [k, dates[k]]),
  );
  await mkdir(dirname(outFile), { recursive: true });
  await writeFile(outFile, `${JSON.stringify(sorted, null, 2)}\n`, 'utf-8');
  console.log(
    `build-git-dates: wrote ${relative(repoRoot, outFile)} (${Object.keys(sorted).length} projects).`,
  );
}

main().catch((e) => {
  console.error(e?.stack || e?.message || e);
  process.exit(1);
});
